import unittest
from core import BaseHandler
from service import DataService

class TestMultiFile(unittest.TestCase):
    def test_interface_adherence(self):
        ds = DataService()
        meta = {'source': 'test'}
        ds.process("data", meta)
        self.assertEqual(ds.last_metadata, meta)

    def test_inheritance(self):
        self.assertTrue(issubclass(DataService, BaseHandler))

if __name__ == '__main__':
    unittest.main()
